{
  "schema": "brainflow.procedural_config.v1",
  "id": "arglen_mitigation",
  "description": "Prefer temp-file payloads and short CLI args on Windows to avoid arg-length limits.",
  "rules": {
    "prefer_temp_payload_file": true,
    "max_inline_arg_chars": 4096,
    "temp_payload_dir": "memory/procedural/tmp",
    "delete_temp_after_use": true
  }
}
